mapper.select:
SELECT id, account_id, currency, available_amount
FROM account_balance
WHERE account_id = #{accountId}

mapper.update:
UPDATE account_balance
SET available_amount = #{availableAmount}
WHERE id = #{id}

mapper.select:
SELECT id, account_id, currency, available_amount
FROM account_balance
WHERE account_id = #{accountId}
  AND currency = #{currency, typeHandler=org.apache.ibatis.type.EnumTypeHandler}
